package com.ruoyi.modules.invest.benefit.evaluation.controller;
import com.ruoyi.common.annotation.Log;import com.ruoyi.common.core.controller.BaseController;import com.ruoyi.common.core.domain.AjaxResult;import com.ruoyi.common.core.page.TableDataInfo;import com.ruoyi.common.enums.BusinessType;import com.ruoyi.modules.invest.benefit.evaluation.domain.InvestBenefitEvaluation;import com.ruoyi.modules.invest.benefit.evaluation.service.IInvestBenefitEvaluationService;import org.apache.shiro.authz.annotation.RequiresPermissions;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/invest/benefit/evaluation")public class InvestBenefitEvaluationController extends BaseController{@Autowired private IInvestBenefitEvaluationService service;@RequiresPermissions("invest:benefit:evaluation:list")@GetMapping("/list")public TableDataInfo list(InvestBenefitEvaluation e){startPage();return getDataTable(service.selectList(e));}@RequiresPermissions("invest:benefit:evaluation:list")@GetMapping("/{id}")public AjaxResult get(@PathVariable Long id){return success(service.selectById(id));}@RequiresPermissions("invest:benefit:evaluation:add")@Log(title="投后评估",businessType=BusinessType.INSERT)@PostMapping public AjaxResult add(@RequestBody InvestBenefitEvaluation e){return toAjax(service.insert(e));}@RequiresPermissions("invest:benefit:evaluation:edit")@PutMapping public AjaxResult edit(@RequestBody InvestBenefitEvaluation e){return toAjax(service.update(e));}@RequiresPermissions("invest:benefit:evaluation:remove")@DeleteMapping("/{ids}")public AjaxResult del(@PathVariable Long[] ids){return toAjax(service.deleteByIds(ids));}@RequiresPermissions("invest:benefit:evaluation:edit")@PostMapping("/{id}/calculate")public AjaxResult calculate(@PathVariable Long id){return toAjax(service.calculate(id));}}